-- Vytvorenie tabuľky skoly
CREATE TABLE skoly (
    IdSkola INT PRIMARY KEY,
    Nazov VARCHAR(50),
    Nazov_short VARCHAR(50),
    Ulica VARCHAR(50),
    FkIdObec INT,
    FkIdTypZriad INT,
    FkIdPodtypSkoly INT,
    SurX FLOAT,
    SurY FLOAT,
    Web VARCHAR(60),
    FOREIGN KEY (FkIdObec) REFERENCES cisObceOkresy(IdObec),
    FOREIGN KEY (FkIdTypZriad) REFERENCES cisTypZriad(IdTypZriad),
    FOREIGN KEY (FkIdPodtypSkoly) REFERENCES cisPodtypSkoly(IdPodtypSkoly)
);

-- Vloženie dát do tabuľky skoly
